import React, { useEffect, useState } from "react";
import { Link, useLocation } from "react-router-dom";
import "../Register.css";

const typeDescriptions = {
  ENFP: "„აღმომჩენი“ - ენერგიული, კრეატიული და მხნე...",
  ISTJ: "„ლოჯისტიკოსი“ - პრაქტიკული და საიმედო...",
  INFJ: "„მრჩეველი“ - სულიერად მდიდარი და მზრუნველი...",
  ESFP: "„პერფორმერი“ - ენერგიული და მეგობრული...",
  INFP: "„მედიატორი“ - მგრძნობიარე და იდეალისტი...",
  ESTJ: "„მმართველი“ - ორგანიზებული და ლიდერი...",
  ENFJ: "„პროტაგონისტი“ - კომუნიკაბელური და შთამაგონებელი...",
  ISFP: "„თავგადასავლების მოყვარული“ - მშვიდი და შემოქმედებითი...",
  ISTP: "„ვირტუოზი“ - პრაქტიკული და ტექნიკური...",
  ESFJ: "„კონსული“ - სოციალური და მზრუნველი...",
  ENTJ: "„კომანდირი“ - მიზანდასახული ლიდერი...",
  INTJ: "„არქიტექტორი“ - სტრატეგიული და ანალიტიკური...",
  ESTP: "„მეწარმე“ - აქტიური და რისკიანი...",
  ENTP: "„ინოვატორი“ - იდეებით სავსე...",
  ISFJ: "„დამცველი“ - ერთგული და პასუხისმგებლიანი...",
  INTP: "„ლოგიკოსი“ - ლოგიკური და ცნობისმოყვარე..."
};

export default function FinalResults({ results }) {
  const [user, setUser] = useState(false);
  const [saved, setSaved] = useState(false);
  const [type, setType] = useState("");
  const [articles, setArticles] = useState([]);

  const location = useLocation();

  /* ---------- MBTI TYPE ---------- */
  useEffect(() => {
    const token = localStorage.getItem("auth_token");
    if (token) setUser(true);

    if (localStorage.getItem("savedResult")) setSaved(true);

    let calculated =
      (results?.EI || "") +
      (results?.SN || "") +
      (results?.TF || "") +
      (results?.JP || "");

    if (!calculated || calculated.length !== 4) {
      const params = new URLSearchParams(location.search);
      calculated = params.get("type") || "";
    }

    if (!calculated || calculated.length !== 4) {
      calculated = localStorage.getItem("pendingResult") || "";
    }

    if (calculated.length === 4) {
      setType(calculated);
      localStorage.setItem("pendingResult", calculated);
    }
  }, [results, location]);

  /* ---------- ARTICLES FETCH ---------- */
  useEffect(() => {
    if (!type) return;

    fetch(`http://localhost:5000/api/articles?type=${type}`)
      .then(res => res.json())
      .then(data => setArticles(data))
      .catch(() => setArticles([]));
  }, [type]);

  /* ---------- SAVE BUTTON ---------- */
  const toggleSave = () => {
    if (!type) return;

    if (saved) {
      localStorage.removeItem("savedResult");
      setSaved(false);
    } else {
      localStorage.setItem("savedResult", type);
      setSaved(true);
    }
  };

  if (!type) return <p>Loading...</p>;

  return (
    <div className="result-layout">

      {/* MAIN RESULT CARD */}
      <div className="register-page">
        <div className="register-card">

          {user && (
            <img
              src={saved ? "/save1.png" : "/save.png"}
              className="save-icon-result"
              onClick={toggleSave}
              alt="save"
            />
          )}

          <img
            className="result-image"
            src={`/images/types/${type}.png`}
            alt={type}
          />

          <h2 className="register-title">{type}</h2>

          <p className="register-description">
            {typeDescriptions[type]}
          </p>

          {!user && (
            <p className="register-text">
              მონაცემების შესანახად{" "}
              <Link
                to="/register"
                className="register-link"
                onClick={() => localStorage.setItem("pendingResult", type)}
              >
                გაიარე რეგისტრაცია
              </Link>
            </p>
          )}

        </div>
      </div>

      {/* RIGHT SIDEBAR ARTICLES */}
      {articles.length > 0 && (
        <div className="articles-sidebar">
          <h3>სტატიები {type} ტიპისთვის</h3>

          {articles.map(a => (
            <Link
              key={a.slug}
              to={`/articles/${a.slug}`}
              className="article-card"
            >
              <b>{a.title}</b>
              <p>{a.excerpt}</p>
            </Link>
          ))}
        </div>
      )}

    </div>
  );
}
